const now = new Date().toISOString();
const sessionId = `smoke-${Date.now()}`;
return [{
  json: {
    session_id: sessionId,
    question: 'smoke: ping',
    user_id: 'smoke-check',
    token: $env.AGENT_WORKFLOW_TOKEN || '',
    run_at: now
  }
}];

if ($json.error) {
  const message = String($json.error.message ?? $json.error ?? 'unknown upstream error');
  throw new Error('agent_query_main call failed: ' + message);
}
const rawBody = $json.body ?? $json.data ?? $json.response ?? $json;
let payload = rawBody;
if (typeof rawBody === 'string') {
  const text = rawBody.trim();
  if (!text) throw new Error('agent_query_main returned empty body');
  try {
    payload = JSON.parse(text);
  } catch {
    throw new Error('agent_query_main returned non-JSON body: ' + text.slice(0, 300));
  }
}
if (!payload || typeof payload !== 'object') {
  throw new Error('agent_query_main returned unexpected payload type');
}
const answer = String(payload.answer ?? '').trim();
if (!answer) {
  throw new Error('agent_query_main returned payload without answer');
}
return [{
  json: {
    session_id: String(payload.session_id ?? $json.session_id ?? ''),
    answer
  }
}];
